package typeCasting;

public class es3 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		/*
		 * Scrivi un programma Java che dichiara una variabile 
		 * di tipo int chiamata "numeroIntero" e una variabile 
		 * di tipo String chiamata "numeroStringa". Esegui un cast 
		 * della variabile "numeroIntero" in String e assegna il 
		 * valore risultante alla variabile "numeroStringa". 
		 * Stampa il valore della variabile "numeroStringa".
		 */
		
		int numeroIntero = 10;
		String numeroStringa = String.valueOf(numeroIntero);
		System.out.println(numeroStringa);
	}

}
